bands.onBeforePrint:
Definir Cursor Cur_R038HFI;
Definir Data vFimCmp;

@ -- Iniciar Variávies -- @
  vNumEmp = R034FUN.NumEmp;
  vTipCol = R034FUN.Tipcol;
  vNumCad = R034FUN.NumCad;
  vFimCmp = xFimCmp;

/* Variáveis carregadas na pré seleção @
  xIniCmp, xFimCmp, 
*/

@ -- Zerar váriaveis que serão utilizadas pelo Totalizador @ 
  @-- Datas --@
  vDatDem  = 0;          
  vDatAdm  = 0;
  vDatAlt  = 0;
  @-- Sados --@
  fSldMes2 = 0;
  FSldMes1 = 0;
  @  Controle @
  FAdmMes  = 0;
  FDemMes  = 0;
  xTransf  = 0;
  xAdm     = 0;
  xDem     = 0;
  @  Situação @
  xTipSit  = 0;
  xFilAnt  = 0;
  xFil     = 0;


@------------------------------------------------------------------------------@
@    1º - Definir Datas de Adm e Demissão                                      @  
@------------------------------------------------------------------------------@ 
  @Verifica Ultimo histórico do colaborador, somente até o final da competencia@
  @R038HFI.DATALT <= :vFimCmp AND @
  Cur_R038HFI.SQL 
        "SELECT R038HFI.NUMEMP, R038HFI.TIPCOL, R038HFI.NUMCAD ,R038HFI.DATALT ,\
         R038HFI.CODFIL FROM R038HFI WHERE R038HFI.DATALT <= :vFimCmp AND R038HFI.TIPCOL = :vTipCol AND R038HFI.EMPATU = :vNumEmp \
         AND R038HFI.CADATU = :vNumCad ORDER BY R038HFI.DATALT Desc ";
  Cur_R038HFI.AbrirCursor();

  Se(Cur_R038HFI.Achou)
  Inicio
    xfil = Cur_R038HFI.CODFIL; 
    vDatAlt = Cur_R038HFI.DATALT;
    Se(R038HFI.CODFIL <> xfil)
      vDatAdm = R038HFI.DATALT;
    senao
      vDatAdm = R034FUN.DATADM;
  Fim  
  Senao
  Inicio
    vDatAlt = R038HFI.DATALT;
    vDatAdm = R034FUN.DATADM;
    xfil    = R038HFI.CODFIL;     
  Fim
  Cur_R038HFI.FecharCursor();  

  @Valores para conferencia@
  fAlt = vDatAlt;
  fAdm = vDatAdm;  
  fFil = xFil;

  @ situação no histórico de filial@
  xtipsit = R010SIT.TIPSIT;

  @ Ajustar Data de Demissão @
  se(xtipsit = 7)
    vDatDem = R034FUN.DatAfa; 
  fDem = vDatDem ;  

  @ Definir a Filial da competencia Anterior @
  RetFilEmp (vNumEmp, vTipCol, vNumCad, ERefAnt );
  xFilAnt = filemp;   
  fAnt = xFilAnt;

  @---------- Exceções colaboradores que não devem ser listados-------------@
  Se((R022VIN.CONGED <> 'S')OU(R034FUN.TIPCOL = 2) OU (R034FUN.TIPCON = 11)OU 
    (R034FUN.TIPCON = 12))
    VAPARA Desconsidera;

  @-------- Verificar se é Transferencia ----------@
  Se ((vDatAlt >= xIniCmp ) E (vDatAlt <= xFimCmp ))
  Inicio
    xTransf = 1;
  Fim
  Senao
    xTransf = 0;

  @------ Verificar se é demitido no mesref -------@
  Se ((vDatDem >= xIniCmp ) E (vDatDem <= xFimCmp ))
  Inicio
    xDem = 1;
  Fim
  Senao
    xDem = 0;  

  @------ Verificar se é admintido no mesref ------@
  Se ((vDatAdm >= xIniCmp ) E (vDatAdm <= xFimCmp ))
  Inicio
    xAdm = 1;
  Fim
  Senao
    xAdm = 0;           

@------------------------------------------------------------------------------@  
@   2º - Verificar colaboradores na competência anterior                       @ 
@------------------------------------------------------------------------------@
  @ Colaboradores ativos no inicio do 1º mes @
  Se (vDatAdm < xIniCmp)
  Inicio
    Se(NumCadMes1 <> R034FUN.NUMCAD)
    Inicio
      Se(((xtipsit <> 7) E (xTransf = 1) E (R038HFI.CODFIL = xFilAnt))ou 
        (( xtipsit <> 7) E (xTransf = 0) E(R038HFI.CODFIL = xFilAnt)))
      Inicio
        FSldMes1 = 1;
        NumCadMes1 = R034FUN.NUMCAD;
      fim  
      Senao
      Se((xtipsit = 7) E (vDatDem >= xIniCmp) E (xTransf = 1) E (R038HFI.CODFIL <> xFilAnt) ou
         (xtipsit = 7) E (vDatDem >= xIniCmp) E (xTransf = 0) E (R038HFI.CODFIL = xFilAnt))
      Inicio
        FSldMes1 = 1;
        @ Carregar variávies que informa o ultimo reg. listado @
        NumCadMes1 = R034FUN.NUMCAD;
      Fim  
    fim
  Fim
@------------------------------------------------------------------------------@  
@    Colaboradores Ativos na competência de referência                         @       
@------------------------------------------------------------------------------@    
  Se  (vDatAdm <= xfimCmp)
  Inicio
    Se(NumCadMes2 <> R034FUN.NUMCAD)
    Inicio
        Se(((xtipsit <> 7) E (xTransf = 1) E (R038HFI.CODFIL <> xFilAnt) E (R038HFI.CODFIL = xFil))OU
           ((xtipsit <> 7) E (xTransf = 0) E (R038HFI.CODFIL = xFilAnt)))        
        Inicio  
          FSldMes2 = 1;
          NumCadMes2 = R034FUN.NUMCAD;
        Fim  
        Senao  
        Se((xtipsit = 7) E (vDatDem > xFimCmp) E (R038HFI.CODFIL = xFil))
        Inicio  
          FSldMes2 = 1;
          NumCadMes2 = R034FUN.NUMCAD;
        Fim  
    Fim      
  fim

@------------------------------------------------------------------------------@  
@    3º - Verificar Demissões e Admissões por transferência na Competência     @ 
@------------------------------------------------------------------------------@       
  Se  (vDatAdm <= xfimCmp)
  Inicio 
    @ -------------------- Admitidos por Transferência ----------------------- @
    SE (FunAdm <> R034FUN.NUMCAD)
    Inicio
      Se(((xTransf = 1) E (xtipsit <> 7) E (R038HFI.CODFIL <> xFilAnt) E (R038HFI.CODFIL = xFil) ) OU
        ((xAdm    = 1) E (xtipsit = 7) E (xFilAnt = 0)) ou
        ((xTransf = 1) E (xtipsit  = 7) E (R038HFI.CODFIL = xFilAnt) E (vDatDem > xFimCmp)))
      Inicio
        FAdmMes = 1;
        FunAdm =  R034FUN.NUMCAD;
      Fim 
    Fim

    @ ------------ Demitidos por Transferência na Competencia ---------------- @
    SE (FunDem <> R034FUN.NUMCAD)
    Inicio  
      Se(((xTransf = 1) E (R038HFI.CODFIL <> xFil) E(R038HFI.CODFIL = xFilAnt)) OU
        ((xDem = 1) E ((R038HFI.CODFIL = xFilAnt) ou (xFilAnt = 0)))) 
      Inicio
        FunDem =  R034FUN.NUMCAD;
        FDemMes = 1;
      Fim 
    Fim
  Fim  
@------------------------------------------------------------------------------@

  @ Desconsidera Exeções @
  Desconsidera:

